// [시간 기반 고도화 버전]
IsGapUp = DayOpen() >= PreDayClose();

// 9시 10분/30분 기점을 시간으로 포착
Mark10 = (Time >= 091000) and (Time(1) < 091000);
Mark30 = (Time >= 093000) and (Time(1) < 093000);

// 음봉 상태 확정
Is10MinNeg = ValueWhen(1, Mark10, DayOpen() > C);
Is30MinNeg = ValueWhen(1, Mark30, DayOpen() > C);

// 시가 상향 돌파 시 매수
Cond10 = IsGapUp and Is10MinNeg and (Time >= 091000) and CrossUp(C, DayOpen());
Cond30 = IsGapUp and Is30MinNeg and (Time >= 093000) and CrossUp(C, DayOpen());

